function PrintReport()
{
	//Ctrl("UrlControl02").Print();

	var options = "resizable=yes,scrollbars=yes,status=yes,menubar=yes,toolbar=yes,location=no,directories=no,";
  if (window.screen)
  options += "width=" + (window.screen.availWidth - 100) + ",height=" + (window.screen.availHeight - 100);
  options += ",screenX=0,screenY=0,top=0,left=0";

  newWin = window.open("../../../tempfiles/" + Ctrl("UrlControl02").GetXValue(), "NucleusRH", options);
  setTimeout("newWin.print()", 500);

}

