function ShowFichadas(oi_personal_emp, f_ini, f_fin, id, flow)
{	
	openNewFlowWait(flow,"initreport","<FILTRO oi_personal_emp=\""+oi_personal_emp+"\" id=\""+id+"\" f_ini=\""+f_ini+"\" f_fin=\""+f_fin+"\" />",new ObjtectResult(),"L");
}

function ShowLegajo(oi_personal_emp, flow)
{
	openNewFlowWait(flow,"initreport","<ROWS><ROW id=\""+oi_personal_emp+"\"/></ROWS>",new ObjtectResult(),"L");
}
